<?php
namespace App\Models;use App\Domain\Inventory\Instances\ItemInstanceEventType;use Illuminate\Database\Eloquent\Factories\HasFactory;use Illuminate\Database\Eloquent\Model;use LogicException;
class ItemInstanceEvent extends Model{use HasFactory;public $timestamps=false;protected $guarded=[];protected $casts=['metadata'=>'array','occurred_at'=>'datetime','created_at'=>'datetime'];protected static function booted(){static::creating(function($m){if(in_array($m->event_type,[ItemInstanceEventType::CREATED_FROM_HUNT_REWARD,ItemInstanceEventType::CREATED_FROM_COMBAT_REWARD,ItemInstanceEventType::CREATED_FROM_SHOP_PURCHASE,ItemInstanceEventType::IMPORTED_FROM_LEGACY_INVENTORY],true)&&(!$m->source_type||!$m->source_id))throw new LogicException('Birth events require a source.');});static::updating(function(){throw new LogicException('ItemInstanceEvent is append-only.');});static::deleting(function(){throw new LogicException('ItemInstanceEvent is append-only.');});}public function itemInstance(){return$this->belongsTo(ItemInstance::class);}}
